@if (isVisible)
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="title" />
        <input type="text" placeholder="Assignee" @bind="assignee" />
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="dueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="HandleSave" disabled="@isSaving">Save</button>
            <button class="btn-cancel" @onclick="HandleCancel">Cancel</button>
        </div>
    </div>
}
else
{
    <button class="btn-add-task" @onclick="ShowForm">Add Task</button>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool isVisible;
    private bool isSaving;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today;

    private void ShowForm() => isVisible = true;

    private void HandleCancel()
    {
        isVisible = false;
        ResetForm();
    }

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title))
            return;

        isSaving = true;
        await OnTaskCreated.InvokeAsync(
            new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status));
        isSaving = false;
        isVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today;
    }
}

