    padding: 0.75rem;
    box-shadow: 0 1px 2px rgba(0,0,0,0.1);
}

.task-card h4 {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

.task-assignee {
    margin: 0 0 0.25rem;
