    border-radius: 3px;
    font-size: 0.75rem;
    font-weight: 600;
    margin-right: 0.5rem;
}

.priority-high {
    background: #fee2e2;
    color: #dc2626;
}

.priority-medium {
    background: #fef9c3;
    color: #ca8a04;
}

.priority-low {
    background: #dcfce7;
    color: #16a34a;
}

.task-due {
    font-size: 0.8rem;
    color: #777;
}

.task-actions {
    margin-top: 0.5rem;
    display: flex;
    gap: 0.5rem;
}

.btn-move {
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    border: 1px solid #ccc;
    border-radius: 3px;
    background: #fff;
    cursor: pointer;
}

.btn-move:hover {
    background: #eee;
}

.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #e8eaf0;
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat {
    font-size: 0.9rem;
    font-weight: 600;
}

.stat-overdue {
    color: #dc2626;
}

.board-search {
    margin-bottom: 1rem;
}

.board-search input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    padding: 0.5rem;
    background: #fff;
    border-radius: 4px;
    border: 1px dashed #ccc;
}

.add-task-form input,
.add-task-form select {
    padding: 0.35rem;
    border: 1px solid #ccc;
    border-radius: 3px;
    font-size: 0.85rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-save {
    padding: 0.3rem 0.75rem;
    background: #2563eb;
    color: #fff;
    border: none;
    border-radius: 3px;
    cursor: pointer;
}

.btn-save:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-cancel {
    padding: 0.3rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 3px;
    background: #fff;
    cursor: pointer;
}

.btn-add-task {
    width: 100%;
    padding: 0.4rem;
    border: 1px dashed #bbb;
    border-radius: 4px;
    background: transparent;
    color: #555;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-add-task:hover {
    background: #e9e9e9;
}

.error-message {
    color: #dc2626;
    padding: 0.75rem;
    background: #fee2e2;
    border-radius: 4px;
}

