 @page "/board"
 @rendermode InteractiveServer
 @using sv_1c96c935cc084dc5bf40defa971142fd.Components.Board
 @inject ITaskService TaskService

 <PageTitle>Kanban Board</PageTitle>

 @if (isLoading)
 {
     <p>Loading board...</p>
 }
 else if (errorMessage is not null)
 {
     <p class="error-message">@errorMessage</p>
 }
 else
 {
     <BoardStats Total="allTasks.Count"
                 ToDo="CountByStatus("To Do")"
                 InProgress="CountByStatus("In Progress")"
                 DoneCount="CountByStatus("Done")"
                 Overdue="allTasks.Count(t => t.DueDate < DateTime.Today)" />

     <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearch" />

     <div class="board-columns">
         <BoardColumn Title="To Do" Status="To Do"
                      Tasks="FilteredByStatus("To Do")"
                      ShowMoveLeft="false" ShowMoveRight="true"
                      OnMoveRight="@(t => MoveTask(t, "In Progress"))"
                      OnTaskCreated="HandleTaskCreated" />

         <BoardColumn Title="In Progress" Status="In Progress"
                      Tasks="FilteredByStatus("In Progress")"
                      ShowMoveLeft="true" ShowMoveRight="true"
                      OnMoveLeft="@(t => MoveTask(t, "To Do"))"
                      OnMoveRight="@(t => MoveTask(t, "Done"))"
                      OnTaskCreated="HandleTaskCreated" />

         <BoardColumn Title="Done" Status="Done"
                      Tasks="FilteredByStatus("Done")"
                      ShowMoveLeft="true" ShowMoveRight="false"
                      OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
                      OnTaskCreated="HandleTaskCreated" />
     </div>
 }

 @code {
     private List<TaskItem> allTasks = [];
     private string searchText = "";
     private bool isLoading = true;
     private string? errorMessage;

     protected override async Task OnInitializedAsync()
     {
         try
         {
             allTasks = await TaskService.GetAllTasksAsync();
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to load tasks: {ex.Message}";
         }
         finally
         {
             isLoading = false;
         }
     }

     private int CountByStatus(string status) =>
         allTasks.Count(t => t.Status == status);

     private IReadOnlyList<TaskItem> FilteredByStatus(string status) =>
         allTasks
             .Where(t => t.Status == status &&
                 (string.IsNullOrWhiteSpace(searchText) ||
                  t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)))
             .ToList();

     private void HandleSearch(string text) => searchText = text;

     private async Task MoveTask(TaskItem task, string newStatus)
     {
         try
         {
             await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
             var index = allTasks.FindIndex(t => t.Id == task.Id);
             if (index >= 0)
                 allTasks[index] = task with { Status = newStatus };
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to move task: {ex.Message}";
         }
     }

     private async Task HandleTaskCreated(TaskItem placeholder)
     {
         try
         {
             var created = await TaskService.CreateTaskAsync(
                 placeholder.Title, placeholder.Assignee, placeholder.Priority, placeholder.DueDate);
             allTasks.Add(created);
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to create task: {ex.Message}";
         }
     }
 }

